"use client";

import { type CalloutFrame, type CalloutProps, Callout as CalloutRoot } from "./callout";
import { CalloutContent, type CalloutContentProps } from "./callout-content";
import { CalloutDismiss, type CalloutDismissProps } from "./callout-dismiss";
import { CalloutIcon, type CalloutIconProps } from "./callout-icon";
import { CalloutTitle, type CalloutTitleProps } from "./callout-title";

/**
 * Dismissible alert box with tone-driven coloring, frame variants (inline / rail / bar), and a
 * compound API.
 */
const Callout = Object.assign(CalloutRoot, {
  Icon: CalloutIcon,
  Title: CalloutTitle,
  Content: CalloutContent,
  Dismiss: CalloutDismiss,
});

export { Callout, type CalloutProps, type CalloutFrame };
export type { CalloutTone } from "./callout-context";
export { CalloutIcon, type CalloutIconProps };
export { CalloutTitle, type CalloutTitleProps };
export { CalloutContent, type CalloutContentProps };
export { CalloutDismiss, type CalloutDismissProps };

"use client";

import { createContext, useContext } from "react";

/** Allowed callout tone values. */
export type CalloutTone = "info" | "warning" | "error" | "success";

/** Context value shared by callout. */
export interface CalloutContextValue {
  /** Semantic tone - drives color and default icon. */
  tone: CalloutTone;
  /** Called when dismiss occurs. */
  onDismiss: () => void;
}

/** React context backing callout. */
export const CalloutContext = createContext<CalloutContextValue | undefined>(undefined);

/** Reads the callout context. */
export function useCalloutContext() {
  const context = useContext(CalloutContext);
  if (!context) {
    throw new Error("Callout compound components must be used within a Callout");
  }
  return context;
}

"use client";

import { getRestorableFocusTarget } from "@/hooks/utils/focus-restore";
import { isFocusable } from "@/hooks/utils/focusable";
import {
  Children,
  type ComponentProps,
  Fragment,
  isValidElement,
  type ReactNode,
  useCallback,
  useMemo,
  useRef,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useControllableState } from "@/hooks/use-controllable-state";
import { cn } from "@/lib/utils";
import { CalloutContext, type CalloutTone } from "./callout-context";
import { CalloutIcon } from "./callout-icon";

/** Allowed callout frame values. */
export type CalloutFrame = "inline" | "rail" | "bar";

const TONE_LABEL: Record<CalloutTone, string> = {
  info: "Info: ",
  warning: "Warning: ",
  error: "Error: ",
  success: "Success: ",
};

const TONE_ROLE_LIVE: Record<CalloutTone, "status" | "alert"> = {
  info: "status",
  warning: "status",
  success: "status",
  error: "alert",
};

const DISMISS_FOCUS_SELECTOR = [
  "a[href]",
  "button:not([disabled])",
  'input:not([type="hidden"]):not([disabled])',
  "select:not([disabled])",
  "textarea:not([disabled])",
  "[tabindex]:not([disabled])",
].join(",");

function getFocusSearchScope(root: HTMLElement): ParentNode {
  const rootNode = root.getRootNode();
  const view = root.ownerDocument.defaultView;
  if (view && rootNode instanceof view.ShadowRoot) return rootNode;
  return root.ownerDocument.body;
}

function getDismissFocusTargets(root: HTMLElement): HTMLElement[] {
  const ownerDocument = root.ownerDocument;
  const candidates = Array.from(
    getFocusSearchScope(root).querySelectorAll<HTMLElement>(DISMISS_FOCUS_SELECTOR),
  ).filter((candidate) => !root.contains(candidate) && isFocusable(candidate));
  const NodeCtor = ownerDocument.defaultView?.Node;
  const followingFlag = NodeCtor?.DOCUMENT_POSITION_FOLLOWING ?? 4;
  const precedingFlag = NodeCtor?.DOCUMENT_POSITION_PRECEDING ?? 2;

  const following = candidates.filter((candidate) =>
    Boolean(root.compareDocumentPosition(candidate) & followingFlag),
  );
  const preceding = candidates
    .filter((candidate) => Boolean(root.compareDocumentPosition(candidate) & precedingFlag))
    .reverse();
  return [...following, ...preceding];
}

function moveFocusOutsideCallout(root: HTMLElement): void {
  for (const target of getDismissFocusTargets(root)) {
    target.focus({ preventScroll: true });
    const activeElement = getRestorableFocusTarget(root.ownerDocument);
    if (activeElement && !root.contains(activeElement)) return;
  }
}

function hasCalloutIcon(children: ReactNode): boolean {
  let found = false;
  Children.forEach(children, (child) => {
    if (found) return;
    if (!isValidElement<{ children?: ReactNode }>(child)) return;
    if (child.type === CalloutIcon) {
      found = true;
      return;
    }
    if (child.type === Fragment) found = hasCalloutIcon(child.props.children);
  });
  return found;
}

/** Props for callout. */
export interface CalloutProps extends ComponentProps<"div"> {
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Semantic tone - drives color and default icon. */
  tone?: CalloutTone;
  /** Visual frame: inline border, inline-start rail, or marker bar. */
  frame?: CalloutFrame;
  /** Controlled visibility state. Pair with onOpenChange. */
  open?: boolean;
  /** Initial visibility state for uncontrolled usage. */
  defaultOpen?: boolean;
  /** Called when Callout.Dismiss closes the callout or controlled state should change. */
  onOpenChange?: (open: boolean) => void;
  /** Opt into role="status" (or role="alert" for tone="error") for live-region announcement. */
  live?: boolean;
  /** Screen-reader tone word announced before the content. Defaults to the tone name. */
  toneLabel?: string;
}

/**
 * Dismissible alert box with tone-driven coloring, frame variants (inline / rail / bar), and a
 * compound API.
 */
export function Callout({
  className,
  tone = "info",
  frame = "inline",
  open: controlledOpen,
  defaultOpen,
  onOpenChange,
  live = false,
  toneLabel,
  ref,
  children,
  ...props
}: CalloutProps) {
  const rootRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);
  const [open, setOpen] = useControllableState({
    value: controlledOpen,
    defaultValue: defaultOpen ?? true,
    onChange: onOpenChange,
  });

  const onDismiss = useCallback(() => {
    const root = rootRef.current;
    const activeElement = root ? getRestorableFocusTarget(root.ownerDocument) : null;

    if (root && activeElement && root.contains(activeElement)) {
      moveFocusOutsideCallout(root);
    }

    setOpen(false);
  }, [setOpen]);
  const contextValue = useMemo(() => ({ tone, onDismiss }), [tone, onDismiss]);

  if (!open) return null;

  const hasIcon = hasCalloutIcon(children);
  const role = live ? TONE_ROLE_LIVE[tone] : undefined;

  return (
    <CalloutContext value={contextValue}>
      <div
        ref={composedRef}
        role={role}
        data-slot="callout"
        data-tone={tone}
        data-frame={frame}
        className={cn(className)}
        {...props}
      >
        <div data-slot="callout-grid" data-has-icon={String(hasIcon)}>
          {frame === "bar" && (
            <span
              aria-hidden="true"
              data-slot="callout-bar"
              className="self-stretch w-1 rounded-[1px] bg-[color:var(--callout-tone,var(--foreground))] forced-colors:bg-[CanvasText]"
            />
          )}
          <span className="sr-only">{toneLabel ?? TONE_LABEL[tone]}</span>
          {children}
        </div>
      </div>
    </CalloutContext>
  );
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { type CalloutTone, useCalloutContext } from "./callout-context";

const DEFAULT_ICON: Record<CalloutTone, ReactNode> = {
  info: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <circle cx="8" cy="8" r="7" />
      <path d="M8 5v4M8 11h.01" />
    </svg>
  ),
  warning: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <path d="M8 1.5L15 14H1L8 1.5z" />
      <path d="M8 6v4M8 12h.01" />
    </svg>
  ),
  error: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <circle cx="8" cy="8" r="7" />
      <path d="M5 5l6 6M11 5l-6 6" />
    </svg>
  ),
  success: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <circle cx="8" cy="8" r="7" />
      <path d="M5 8.5l2 2 4-5" />
    </svg>
  ),
};

/** Props for callout icon. */
export interface CalloutIconProps extends ComponentProps<"span"> {
  /** Custom icon content. The icon is decorative and aria-hidden. */
  children?: ReactNode;
}

/** Tone icon - outlined 14px SVG (overridable via children) */
export function CalloutIcon({ children, className, ...props }: CalloutIconProps) {
  const { tone } = useCalloutContext();

  return (
    <span
      aria-hidden="true"
      data-slot="callout-icon"
      className={cn(
        "inline-flex items-center justify-center self-center w-4 h-4 text-[color:var(--callout-tone,var(--foreground))] [&>svg]:w-[14px] [&>svg]:h-[14px]",
        className,
      )}
      {...props}
    >
      {children ?? DEFAULT_ICON[tone]}
    </span>
  );
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { cn } from "@/lib/utils";

/** Props for callout title. */
export interface CalloutTitleProps extends ComponentProps<"span"> {
  /** Title text for the callout. */
  children: ReactNode;
}

/** Bold title text in the tone color. */
export function CalloutTitle({ children, className, ...props }: CalloutTitleProps) {
  return (
    <span
      data-slot="callout-title"
      className={cn(
        "self-center font-bold text-[13px] leading-[1.4] text-[color:var(--callout-tone,var(--foreground))]",
        className,
      )}
      {...props}
    >
      {children}
    </span>
  );
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { cn } from "@/lib/utils";

/** Props for callout content. */
export interface CalloutContentProps extends ComponentProps<"div"> {
  /** Body content for the callout. */
  children: ReactNode;
}

/** Body text in muted color. */
export function CalloutContent({ children, className, ...props }: CalloutContentProps) {
  return (
    <div
      data-slot="callout-content"
      className={cn("text-[12px] leading-[1.55] text-muted-foreground", className)}
      {...props}
    >
      {children}
    </div>
  );
}

"use client";

import type { ButtonHTMLAttributes, ReactNode } from "react";
import { hasAccessibleTextContent } from "@/lib/accessible-text";
import { cn } from "@/lib/utils";
import { useCalloutContext } from "./callout-context";

/** Props for callout dismiss. */
export interface CalloutDismissProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  /** Custom dismiss button content. */
  children?: ReactNode;
}

/** Close button (24×24 with 4px padding) */
export function CalloutDismiss({
  children,
  className,
  onClick,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  ...props
}: CalloutDismissProps) {
  const { onDismiss } = useCalloutContext();
  const fallbackLabel =
    ariaLabel || ariaLabelledBy || hasAccessibleTextContent(children) ? undefined : "Dismiss";

  return (
    <button
      type="button"
      data-slot="callout-dismiss"
      aria-label={ariaLabel || fallbackLabel}
      aria-labelledby={ariaLabelledBy}
      onClick={(e) => {
        onClick?.(e);
        if (!e.defaultPrevented) onDismiss();
      }}
      className={cn(
        "self-center inline-flex items-center justify-center shrink-0",
        "w-6 h-6 p-1 rounded-[var(--radius)] font-mono text-[13px] cursor-pointer",
        "text-muted hover:text-foreground hover:bg-foreground/5",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[color:var(--callout-tone,var(--foreground))] focus-visible:ring-offset-2 focus-visible:ring-offset-background",
        "transition-colors",
        className,
      )}
      {...props}
    >
      {children ?? "[x]"}
    </button>
  );
}

/*
 * Callout primitive styles. Two orthogonal axes drive visual chrome via
 * data-attribute selectors on the callout root:
 *   [data-frame] = inline | rail | bar
 *   [data-tone]  = info | success | warning | error
 *
 * Tone cascades three CSS vars consumed by the icon, title, border, and
 * background:
 *   --callout-tone   foreground / icon / title color signal
 *   --callout-border perimeter color (used by inline + rail frames)
 *   --callout-subtle subtle background tint (used by inline + rail frames)
 *
 * Frame chrome (border, rail, bar background) is selected by [data-frame].
 * Grid layout (grid-template-areas) is driven by [data-frame] combined
 * with [data-has-icon] on the inner grid element. The icon column is
 * collapsed when no <Callout.Icon> child is present.
 *
 * For architectural parity with Panel (panel/panel.css), all chrome and
 * forced-colors fallbacks live in this file; the React component only emits
 * data-attributes.
 */
@layer components {
  /*
   * Default tone values are consumed via var() fallback (not declared on the
   * slot) so an ancestor-scoped override reaches them. Defaults: --callout-tone →
   * var(--foreground); --callout-border → var(--border); --callout-subtle → transparent.
   * The [data-tone] variants below still win.
   */
  [data-slot="callout"] {
    position: relative;
    font-family: var(--font-mono);
    font-size: 13px;
    color: var(--foreground);
    border-radius: var(--radius);
  }

  /* ============================================================
     Tone cascade — paints --callout-tone / --callout-border / --callout-subtle.
     ============================================================ */
  [data-slot="callout"][data-tone="info"] {
    --callout-tone: var(--info-text);
    --callout-border: var(--info-border);
    --callout-subtle: var(--info-subtle);
  }
  [data-slot="callout"][data-tone="success"] {
    --callout-tone: var(--success-text);
    --callout-border: var(--success-border);
    --callout-subtle: var(--success-subtle);
  }
  [data-slot="callout"][data-tone="warning"] {
    --callout-tone: var(--warning-text);
    --callout-border: var(--warning-border);
    --callout-subtle: var(--warning-subtle);
  }
  [data-slot="callout"][data-tone="error"] {
    --callout-tone: var(--error-text);
    --callout-border: var(--error-border);
    --callout-subtle: var(--error-subtle);
  }

  /* ============================================================
     Frame: inline (default) — full hairline border at tone color +
     subtle tone background.
     ============================================================ */
  [data-slot="callout"][data-frame="inline"] {
    border: 1px solid var(--callout-border, var(--border));
    background: var(--callout-subtle, transparent);
    padding: 12px 14px;
  }

  /* ============================================================
     Frame: rail — 2px inline-start rail at tone color, no perimeter,
     square corners, subtle tone background.
     ============================================================ */
  [data-slot="callout"][data-frame="rail"] {
    border: 0;
    border-inline-start: 2px solid var(--callout-border, var(--border));
    background: var(--callout-subtle, transparent);
    border-radius: 0;
    padding: 10px 14px;
  }

  /* ============================================================
     Frame: bar — neutral border + a 4px tone marker bar inside the
     grid (placed in the bar grid-area via the [data-slot="callout-bar"]
     rule below). Background is a 2% foreground wash for subtle elevation
     against the page.
     ============================================================ */
  [data-slot="callout"][data-frame="bar"] {
    border: 1px solid color-mix(in oklab, var(--border) 60%, transparent);
    background: color-mix(in oklab, var(--foreground) 2%, transparent);
    padding: 12px 14px;
  }
}

/* ============================================================
   Grid layout: the inner [data-slot="callout-grid"] element owns the
   grid, with columns + template areas driven by [data-frame] and its
   own [data-has-icon]. Each child takes its cell from its data-slot
   (the React components emit data-attributes only).
   ============================================================ */
@layer components {
  [data-slot="callout-grid"] {
    display: grid;
    align-items: start;
    column-gap: 10px;
    row-gap: 4px;
  }

  /* inline / rail columns. */
  [data-slot="callout-grid"][data-has-icon="false"] {
    grid-template-columns: minmax(0, 1fr) auto;
    grid-template-areas: "title dismiss" "body .";
  }
  [data-slot="callout-grid"][data-has-icon="true"] {
    grid-template-columns: 16px minmax(0, 1fr) auto;
    grid-template-areas: "icon title dismiss" ". body .";
  }

  /* bar frame prepends a 4px marker column. */
  [data-slot="callout"][data-frame="bar"] > [data-slot="callout-grid"][data-has-icon="false"] {
    grid-template-columns: 4px minmax(0, 1fr) auto;
    grid-template-areas: "bar title dismiss" "bar body .";
  }
  [data-slot="callout"][data-frame="bar"] > [data-slot="callout-grid"][data-has-icon="true"] {
    grid-template-columns: 4px 16px minmax(0, 1fr) auto;
    grid-template-areas: "bar icon title dismiss" "bar . body .";
  }

  /* Cell placement per child. */
  [data-slot="callout-bar"] {
    grid-area: bar;
  }
  [data-slot="callout-icon"] {
    grid-area: icon;
  }
  [data-slot="callout-title"] {
    grid-area: title;
  }
  [data-slot="callout-content"] {
    grid-area: body;
  }
  [data-slot="callout-dismiss"] {
    grid-area: dismiss;
  }
}

/* ============================================================
   Forced-colors: keep callout boundaries legible in Windows HCM.
   Mirrors Panel's forced-colors block in panel/panel.css.
   ============================================================ */
@media (forced-colors: active) {
  [data-slot="callout"][data-frame="inline"] {
    border-color: CanvasText;
  }
  [data-slot="callout"][data-frame="rail"] {
    border-inline-start-color: CanvasText;
  }
  [data-slot="callout"][data-frame="bar"] {
    border-color: CanvasText;
  }
}
